using System.Collections.Concurrent;using System.Diagnostics;using System.Security.Cryptography;using System.Text;using AiVideoStudio.Application.Configuration;using AiVideoStudio.Application.Interfaces.Operations;using AiVideoStudio.Application.Interfaces.Render;using AiVideoStudio.Application.Storage;using AiVideoStudio.Domain.Entities;using AiVideoStudio.Domain.Enums;using AiVideoStudio.Domain.Events.Operations;using AiVideoStudio.Domain.Interfaces;using AiVideoStudio.Infrastructure.Export;using AiVideoStudio.Infrastructure.Mongo;using AiVideoStudio.Infrastructure.Render;using AiVideoStudio.Infrastructure.Workflow;using Microsoft.AspNetCore.Http;using Microsoft.Extensions.DependencyInjection;using Microsoft.Extensions.Hosting;using Microsoft.Extensions.Options;using MongoDB.Bson;using MongoDB.Driver;
namespace AiVideoStudio.Infrastructure.Operations;
public sealed class MetricsCollector:IMetricsCollector{private readonly ConcurrentDictionary<string,double> _values=new();private readonly ConcurrentDictionary<string,long> _counts=new();public void Increment(string n,long v=1)=>_values.AddOrUpdate(n,v,(_,x)=>x+v);public void SetGauge(string n,long v)=>_values[n]=v;public void Observe(string n,TimeSpan d){_values.AddOrUpdate(n,d.TotalMilliseconds,(_,x)=>x+d.TotalMilliseconds);_counts.AddOrUpdate(n,1,(_,x)=>x+1);}public IReadOnlyDictionary<string,double> Snapshot(){var result=_values.ToDictionary();foreach(var x in _counts)if(x.Value>0&&result.TryGetValue(x.Key,out var sum))result[$"{x.Key}.average_ms"]=sum/x.Value;return result;}}
public sealed class AuditWriter:IAuditWriter{private readonly IAuditLogRepository _repo;private readonly IRequestContext _context;public AuditWriter(IAuditLogRepository repo,IRequestContext context){_repo=repo;_context=context;}public async Task WriteAsync(string user,AuditActionType action,string result,string resource,CancellationToken ct=default){var log=new AuditLog{UserId=user,Action=$"{action}:{resource}",Result=result,IpAddress=_context.IpAddress??string.Empty,CorrelationId=_context.CorrelationId,TraceId=Activity.Current?.TraceId.ToString()??string.Empty};log.AddDomainEvent(new AuditLogCreatedEvent(log.Id));await _repo.AddAsync(log,ct);}}
public sealed class UsageTracker:IUsageTracker{private readonly IQuotaRepository _repo;public UsageTracker(IQuotaRepository repo)=>_repo=repo;public async Task RecordAsync(string user,QuotaType type,long amount,string resource,CancellationToken ct=default){await _repo.AddUsageAsync(UsageRecord.Create(user,type,amount,resource),ct);var q=await _repo.GetAsync(user,type,ct);if(q is not null){q.Record(amount);await _repo.UpsertAsync(q,ct);}}}
public sealed class NotificationDispatcher:INotificationDispatcher{private readonly INotificationRepository _repo;private readonly IMetricsCollector _metrics;public NotificationDispatcher(INotificationRepository repo,IMetricsCollector metrics){_repo=repo;_metrics=metrics;}public async Task<SystemNotification> DispatchAsync(string user,string title,string message,NotificationType type,CancellationToken ct=default){var n=SystemNotification.Create(user,title,message,type);await _repo.AddAsync(n,ct);_metrics.Increment("notifications.dispatched");return n;}}
public sealed class FixedWindowRateLimiter:IRateLimiter{private sealed record Window(DateTimeOffset Started,int Count);private readonly ConcurrentDictionary<string,Window> _windows=new();private readonly SystemOptions _options;public FixedWindowRateLimiter(IOptions<SystemOptions> options)=>_options=options.Value;public bool TryAcquire(string key){var now=DateTimeOffset.UtcNow;while(true){var old=_windows.GetOrAdd(key,new Window(now,0));var next=now-old.Started>=TimeSpan.FromSeconds(_options.RateLimitWindowSeconds)?new Window(now,1):old with{Count=old.Count+1};if(_windows.TryUpdate(key,next,old))return next.Count<=_options.RateLimitPermitCount;}}}
public sealed class SignedUrlService:ISignedUrlService{private readonly byte[] _key;public SignedUrlService(IOptions<SystemOptions> o)=>_key=Encoding.UTF8.GetBytes(o.Value.SigningKey);public Uri Sign(Uri resource,TimeSpan lifetime){var expires=DateTimeOffset.UtcNow.Add(lifetime).ToUnixTimeSeconds();var separator=string.IsNullOrEmpty(resource.Query)?"?":"&";var unsigned=$"{resource}{separator}expires={expires}";return new Uri($"{unsigned}&signature={Hash(unsigned)}");}public bool Validate(Uri url){var query=Microsoft.AspNetCore.WebUtilities.QueryHelpers.ParseQuery(url.Query);if(!query.TryGetValue("expires",out var e)||!long.TryParse(e,out var expires)||DateTimeOffset.UtcNow.ToUnixTimeSeconds()>expires||!query.TryGetValue("signature",out var signature))return false;var left=url.ToString().Split("&signature=",2)[0];return CryptographicOperations.FixedTimeEquals(Encoding.UTF8.GetBytes(Hash(left)),Encoding.UTF8.GetBytes(signature.ToString()));}private string Hash(string text)=>Convert.ToHexString(HMACSHA256.HashData(_key,Encoding.UTF8.GetBytes(text))).ToLowerInvariant();}
public sealed class RequestContext:IRequestContext,ICorrelationIdProvider{private readonly IHttpContextAccessor _http;public RequestContext(IHttpContextAccessor http)=>_http=http;public string RequestId=>_http.HttpContext?.TraceIdentifier??string.Empty;public string CorrelationId=>_http.HttpContext?.Items["X-Correlation-Id"]?.ToString()??RequestId;public string? UserId=>_http.HttpContext?.User.FindFirst("userId")?.Value;public string? IpAddress=>_http.HttpContext?.Connection.RemoteIpAddress?.ToString();}
public sealed class ProductionHealthCheckService:IHealthCheckService{private readonly MongoDbContext _mongo;private readonly IServiceProvider _services;private readonly IRenderProviderRegistry _providers;private readonly AiVideoStudio.Application.Configuration.StorageOptions _storage;private readonly HealthOptions _options;public ProductionHealthCheckService(MongoDbContext mongo,IServiceProvider services,IRenderProviderRegistry providers,IOptions<AiVideoStudio.Application.Configuration.StorageOptions> storage,IOptions<HealthOptions> options){_mongo=mongo;_services=services;_providers=providers;_storage=storage.Value;_options=options.Value;}public async Task<SystemHealth> CheckAsync(bool readiness,CancellationToken ct=default){if(!readiness)return new(true,DateTimeOffset.UtcNow,[new("process",true)]);var checks=new List<HealthComponent>();using var timeout=CancellationTokenSource.CreateLinkedTokenSource(ct);timeout.CancelAfter(TimeSpan.FromSeconds(_options.TimeoutSeconds));var watch=Stopwatch.StartNew();try{await _mongo.Database.RunCommandAsync<BsonDocument>(new BsonDocument("ping",1),cancellationToken:timeout.Token);checks.Add(new("mongodb",true,null,watch.Elapsed));}catch(Exception ex){checks.Add(new("mongodb",false,ex.GetType().Name,watch.Elapsed));}checks.Add(new("storage",Directory.Exists(Path.GetFullPath(_storage.BasePath)),Path.GetFullPath(_storage.BasePath)));checks.Add(new("provider-registry",_providers.GetProviders().Count>0,$"providers={_providers.GetProviders().Count}"));checks.Add(new("workflow-worker",_services.GetService<WorkflowWorker>() is not null));checks.Add(new("render-worker",_services.GetService<RenderWorker>() is not null));checks.Add(new("export-worker",_services.GetService<ExportWorker>() is not null));return new(checks.All(x=>x.Healthy),DateTimeOffset.UtcNow,checks);}}
public sealed class MaintenanceRunner:IMaintenanceRunner{private readonly MongoDbContext _db;private readonly IMaintenanceRepository _repo;private readonly MaintenanceOptions _o;private readonly AiVideoStudio.Application.Configuration.StorageOptions _storage;private readonly IMetricsCollector _metrics;public MaintenanceRunner(MongoDbContext db,IMaintenanceRepository repo,IOptions<MaintenanceOptions> options,IOptions<AiVideoStudio.Application.Configuration.StorageOptions> storage,IMetricsCollector metrics){_db=db;_repo=repo;_o=options.Value;_storage=storage.Value;_metrics=metrics;}public async Task<MaintenanceTask> RunAsync(string name,string by,CancellationToken ct=default){var task=MaintenanceTask.Create(name,by);await _repo.AddAsync(task,ct);task.Start();await _repo.UpdateAsync(task,ct);try{var now=DateTimeOffset.UtcNow;long count=0;count+=(await _db.UploadSessions.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.UploadRetentionDays),ct)).DeletedCount;count+=(await _db.RenderJobs.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.RenderRetentionDays),ct)).DeletedCount;count+=(await _db.WorkflowExecutions.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.WorkflowRetentionDays),ct)).DeletedCount;count+=(await _db.ExportJobs.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.ExportRetentionDays),ct)).DeletedCount;count+=(await _db.Notifications.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.NotificationRetentionDays),ct)).DeletedCount;count+=(await _db.Database.GetCollection<AuditLog>("AuditLogs").DeleteManyAsync(x=>x.Timestamp<now.AddDays(-_o.AuditRetentionDays),ct)).DeletedCount;count+=(await _db.UsageRecords.DeleteManyAsync(x=>x.CreatedAt<now.AddDays(-_o.UsageRetentionDays),ct)).DeletedCount;var temp=Path.Combine(Path.GetFullPath(_storage.BasePath),"temp");if(Directory.Exists(temp))foreach(var file in Directory.EnumerateFiles(temp,"*",SearchOption.AllDirectories)){ct.ThrowIfCancellationRequested();if(File.GetLastWriteTimeUtc(file)<DateTime.UtcNow.AddHours(-_o.TemporaryFileRetentionHours)){File.Delete(file);count++;}}task.Complete((int)Math.Min(int.MaxValue,count));_metrics.Increment("maintenance.deleted",count);}catch(Exception ex){task.Fail(ex.Message);_metrics.Increment("maintenance.failures");}await _repo.UpdateAsync(task,ct);return task;}}
public sealed class MaintenanceWorker:BackgroundService{private readonly IServiceProvider _services;private readonly MaintenanceOptions _options;public MaintenanceWorker(IServiceProvider services,IOptions<MaintenanceOptions> options){_services=services;_options=options.Value;}protected override async Task ExecuteAsync(CancellationToken ct){if(!_options.Enabled)return;await Task.Delay(TimeSpan.FromSeconds(_options.InitialDelaySeconds),ct);while(!ct.IsCancellationRequested){using var scope=_services.CreateScope();await scope.ServiceProvider.GetRequiredService<IMaintenanceRunner>().RunAsync("scheduled-retention","system",ct);await Task.Delay(TimeSpan.FromMinutes(_options.IntervalMinutes),ct);}}}
